// ═══════════════════════════════════════════════════
// AGENT 1: PREPROCESSOR (Deterministic — no AI)
// CSV row → cleaned dict + messy_text naratif
// Semua logika FIXED — tidak pakai LLM sama sekali
// ═══════════════════════════════════════════════════
const body = $input.first().json;
const raw = body.record || body;

const sf = (v, d=0.0) => { const n=parseFloat(v); return isNaN(n)?d:n; };
const si = (v, d=0) => { const n=parseInt(v); return isNaN(n)?d:n; };

const c = {
  policy_id:            String(raw.ID_policy || raw.policy_id || 'UNKNOWN'),
  insured_id:           String(raw.ID_insured || raw.insured_id || 'UNKNOWN'),
  period:               si(raw.period, 2019),
  premium:              sf(raw.premium, 0),
  cost_claims_year:     sf(raw.cost_claims_year, 0),
  n_medical_services:   si(raw.n_medical_services, 0),
  age:                  si(raw.age, 35),
  gender:               String(raw.gender || 'U').toUpperCase()[0],
  type_policy:          String(raw.type_policy || 'U'),
  type_product:         String(raw.type_product || 'U'),
  reimbursement:        String(raw.reimbursement || 'No'),
  distribution_channel: String(raw.distribution_channel || 'U'),
  C_H:                  String(raw.C_H || 'H1'),
  C_C:                  String(raw.C_C || 'C1'),
  lapse:                si(raw.lapse, 2),
  seniority_insured:    si(raw.seniority_insured, 0),
  exposure_time:        sf(raw.exposure_time, 1.0),
};

// Computed — deterministic, bukan AI
c.loss_ratio = c.premium > 0
  ? Math.round((c.cost_claims_year / c.premium) * 10000) / 10000
  : 0;

// Maps — fixed logic
const polMap  = {I:'Individual', C:'Corporate'};
const prodMap = {S:'Standard', P:'Premium', D:'Dental', I:'International'};
const statMap = {1:'new', 2:'active', 3:'lapsed'};
const chMap   = {I:'online portal', A:'agent/broker', D:'direct sales'};
const rw = c.reimbursement === 'Yes' ? 'reimbursement model' : 'direct billing';

// Build messy_text — simulasi dokumen tidak terstruktur
// Ini yang akan dikirim ke Qwen3 untuk diekstrak kembali
c.messy_text = `HEALTH INSURANCE CLAIM RECORD
==============================
Reference  : POL-${c.policy_id} / INS-${c.insured_id}
Fiscal Year: ${c.period}

POLICYHOLDER INFORMATION
Patient : ${c.gender==='M'?'Male':'Female'}, ${c.age} years old
Policy  : ${polMap[c.type_policy]||c.type_policy} — ${prodMap[c.type_product]||c.type_product}
Channel : ${chMap[c.distribution_channel]||c.distribution_channel}
Tenure  : ${c.seniority_insured} months active
Billing : ${rw}
Exposure: ${c.exposure_time.toFixed(4)}

FINANCIAL SUMMARY
  Annual premium        : EUR ${c.premium.toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2})}
  Total claims this year: EUR ${c.cost_claims_year.toLocaleString('en',{minimumFractionDigits:2,maximumFractionDigits:2})}
  Medical encounters    : ${c.n_medical_services} services

CLASSIFICATION
  Health cluster : ${c.C_H}
  Coverage tier  : ${c.C_C}
  Status code    : ${c.lapse} (${statMap[c.lapse]||'unknown'})`;

return [{ json: c }];

// ═══════════════════════════════════════════════════
// AGENT 3: VALIDATOR + FMR (Deterministic — no AI)
// Compare LLM output vs ground truth → FMR score
// Fixed business rules — routing logic DETERMINISTIC
// ═══════════════════════════════════════════════════
const response = $input.first().json;

// Parse Qwen3 response
let extracted;
try {
  const content = response.choices[0].message.content;
  extracted = typeof content === 'string' ? JSON.parse(content) : content;
} catch(e) {
  return [{ json: { error: 'Failed to parse Qwen3 response: ' + e.message, raw: response } }];
}

// Ground truth dari Agent 1 (deterministic values)
const gt = $('Agent 1: Preprocessor').first().json;

// Comparison helpers — fixed tolerance rules
const near = (a, b, tol=0.05) => {
  const fa = parseFloat(a), fb = parseFloat(b);
  if (isNaN(fa) || isNaN(fb)) return false;
  return Math.abs(fa - fb) <= Math.abs(fb) * tol + 0.01;
};
const sm2 = (a, b) =>
  String(a).trim().toUpperCase().slice(0,2) ===
  String(b).trim().toUpperCase().slice(0,2);

// FMR field checks — each field is deterministic pass/fail
const checks = {
  premium:     near(extracted.premium_eur,         gt.premium),
  cost_claims: near(extracted.cost_claims_eur,     gt.cost_claims_year),
  age:         String(extracted.patient_age)    === String(gt.age),
  gender:      sm2(extracted.patient_gender,       gt.gender),
  services:    String(extracted.n_medical_services) === String(gt.n_medical_services),
  loss_ratio:  near(extracted.loss_ratio,          gt.loss_ratio, 0.1),
  cluster:     sm2(extracted.health_cluster,       gt.C_H),
};

// FMR = correct fields / total fields (deterministic math)
const correct = Object.values(checks).filter(Boolean).length;
const fmr = Math.round((correct / Object.keys(checks).length) * 10000) / 10000;

// Routing decision is DETERMINISTIC (fixed thresholds, not AI)
const recommendation = fmr >= 0.85 ? 'approve' : fmr >= 0.60 ? 'review' : 'reject';

// Business rule flags — fixed logic
const flags = [];
if ((extracted.loss_ratio || 0) > 20) flags.push('extreme_loss_ratio');
if ((extracted.premium_eur || 0) <= 0) flags.push('premium_zero');
if ((extracted.n_medical_services || 0) > 200) flags.push('services_suspicious');

return [{ json: {
  extracted,
  ground_truth: gt,
  fmr,
  fmr_correct: correct,
  fmr_total: Object.keys(checks).length,
  fmr_detail: checks,
  flags,
  recommendation,
  validation: fmr >= 0.80 ? 'PASS' : 'FAIL',
  processed_at: new Date().toISOString(),
} }];

// ═══════════════════════════════════════════════════
// AGENT 4: MONITOR — Fraud & Anomaly Detection
// Semua rule-based DETERMINISTIC — bukan AI
// AI hanya di Agent 2. Semua keputusan lain: fixed logic
// ═══════════════════════════════════════════════════
const data = $input.first().json;
const gt  = data.ground_truth;
const lr  = gt.loss_ratio || 0;
const svc = gt.n_medical_services || 0;
const fmr = data.fmr || 1;
const pid = gt.policy_id || '?';

const alerts = [];

// Rule 1: Extreme loss ratio (deterministic threshold)
if (lr > 5.0) {
  alerts.push({
    severity: 'HIGH',
    type: 'EXTREME_LOSS_RATIO',
    policy_id: pid,
    value: Math.round(lr * 100) / 100,
    message: `Policy ${pid}: loss ratio ${lr.toFixed(2)}x — claims far exceed premium`,
  });
} else if (lr > 2.0) {
  alerts.push({
    severity: 'MEDIUM',
    type: 'HIGH_LOSS_RATIO',
    policy_id: pid,
    value: Math.round(lr * 100) / 100,
    message: `Policy ${pid}: loss ratio ${lr.toFixed(2)}x — needs review`,
  });
}

// Rule 2: High utilization (deterministic threshold)
if (svc > 80) {
  alerts.push({
    severity: 'MEDIUM',
    type: 'HIGH_UTILIZATION',
    policy_id: pid,
    value: svc,
    message: `Policy ${pid}: ${svc} medical services — unusually high utilization`,
  });
}

// Rule 3: Low extraction quality (FMR below threshold)
if (fmr < 0.5) {
  alerts.push({
    severity: 'LOW',
    type: 'LOW_EXTRACTION_QUALITY',
    policy_id: pid,
    value: fmr,
    message: `Policy ${pid}: FMR ${(fmr*100).toFixed(0)}% — manual verification needed`,
  });
}

const high   = alerts.filter(a => a.severity === 'HIGH').length;
const medium = alerts.filter(a => a.severity === 'MEDIUM').length;

return [{ json: {
  ...data,
  monitoring: {
    total_alerts: alerts.length,
    high,
    medium,
    low: alerts.length - high - medium,
    batch_status: high > 0 ? 'CRITICAL' : alerts.length > 0 ? 'REVIEW' : 'CLEAN',
    alerts,
  },
} }];

// Format final output — clean response ke Streamlit
const d = $input.first().json;

const output = {
  id: (() => {
    const arr = new Uint8Array(16);
    for(let i=0;i<16;i++) arr[i]=Math.floor(Math.random()*256);
    arr[6]=(arr[6]&0x0f)|0x40; arr[8]=(arr[8]&0x3f)|0x80;
    return [...arr].map((b,i)=>[4,6,8,10].includes(i)?'-'+b.toString(16).padStart(2,'0'):b.toString(16).padStart(2,'0')).join('');
  })(),
  pipeline_version: '5.0.0-qwen3',
  model_used: 'qwen/qwen3-30b via Groq API',
  processed_at: new Date().toISOString(),
  fmr: d.fmr,
  fmr_correct: d.fmr_correct,
  fmr_total: d.fmr_total,
  fmr_detail: d.fmr_detail,
  recommendation: d.recommendation,
  validation: d.validation,
  risk_flag: d.extracted?.risk_flag || 'UNKNOWN',
  loss_ratio: d.ground_truth?.loss_ratio || 0,
  flags: d.flags || [],
  monitoring: d.monitoring,
  extracted: d.extracted,
  ground_truth: {
    policy_id:        d.ground_truth?.policy_id,
    premium:          d.ground_truth?.premium,
    cost_claims_year: d.ground_truth?.cost_claims_year,
    loss_ratio:       d.ground_truth?.loss_ratio,
    n_medical_services: d.ground_truth?.n_medical_services,
    age:              d.ground_truth?.age,
    gender:           d.ground_truth?.gender,
  },
};

return [{ json: output }];
